// Define a Question class with all properties typed
class Question {
  text: string;
  options: string[]; // Array of possible answers
  correctIndex: number; // Index of the correct option (0-based)
  constructor(text: string, options: string[], correctIndex: number) {
    this.text = text;
    this.options = options;
    this.correctIndex = correctIndex;
  }
  // Check if a given answer index is correct
  isCorrect(answerIndex: number): boolean {
    return answerIndex === this.correctIndex;
  }
}
// Function to display a question and get feedback
function askQuestion(q: Question): void {
  console.log(q.text); // Display question text
  q.options.forEach((opt, i) => { // Loop through options
    console.log(`${i + 1}. ${opt}`); // Print each option
  });
